import { useState, useCallback } from "react";
import { v4 as uuidv4 } from "uuid";
import { seedFeatures } from "../data/seedData";

const STORAGE_KEY = "feature_tracker_data";

function loadFromStorage() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) return JSON.parse(raw);
  } catch (_) {}
  return seedFeatures;
}

function saveToStorage(features) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(features));
  } catch (_) {}
}

export function useFeatures() {
  const [features, setFeatures] = useState(loadFromStorage);

  const persist = useCallback((updated) => {
    setFeatures(updated);
    saveToStorage(updated);
  }, []);

  const addFeature = useCallback(
    (data) => {
      const newFeature = {
        id: uuidv4(),
        title: data.title.trim(),
        description: data.description.trim(),
        priority: data.priority,
        status: data.status,
        createdAt: new Date().toISOString(),
      };
      persist([newFeature, ...features]);
    },
    [features, persist]
  );

  const updateFeature = useCallback(
    (id, data) => {
      persist(
        features.map((f) =>
          f.id === id ? { ...f, ...data } : f
        )
      );
    },
    [features, persist]
  );

  const deleteFeature = useCallback(
    (id) => {
      persist(features.filter((f) => f.id !== id));
    },
    [features, persist]
  );

  const updateStatus = useCallback(
    (id, status) => {
      persist(
        features.map((f) =>
          f.id === id ? { ...f, status } : f
        )
      );
    },
    [features, persist]
  );

  return { features, addFeature, updateFeature, deleteFeature, updateStatus };
}
